#include <stdio.h>
#include <stdlib.h>
#define MAX 200
#define MAX_EDGES 400

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int edges[MAX_EDGES][2];
    for (int i = 0; i < m; i++) {
        scanf("%d %d", &edges[i][0], &edges[i][1]);
    }
    int degrees[n];
    for (int i = 0; i < n; i++) {
        degrees[i] = 0;
    }
    for (int i = 0; i < m; i++) {
        degrees[edges[i][0] - 1]++;
        degrees[edges[i][1] - 1]++;
    }
    int sorted_degrees[n];
    for (int i = 0; i < n; i++) {
        sorted_degrees[i] = i;
    }
    qsort(sorted_degrees, n, sizeof(int), compare);
    int independent_set[n];
    int independent_set_size = 0;
    for (int i = 0; i < n; i++) {
        int is_adjacent = 0;
        for (int j = 0; j < independent_set_size; j++) {
            for (int k = 0; k < m; k++) {
                if ((edges[k][0] == sorted_degrees[i] + 1 && edges[k][1] == independent_set[j] + 1) || (edges[k][0] == independent_set[j] + 1 && edges[k][1] == sorted_degrees[i] + 1)) {
                    is_adjacent = 1;
                    break;
                }
            }
            if (is_adjacent) {
                break;
            }
        }
        if (!is_adjacent) {
            independent_set[independent_set_size] = sorted_degrees[i];
            independent_set_size++;
        }
    }
    int happy_cities = independent_set_size;
    int unhappy_cities = 0;
    for (int i = 0; i < n; i++) {
        int is_unhappy = 0;
        for (int j = 0; j < independent_set_size; j++) {
            for (int k = 0; k < m; k++) {
                if ((edges[k][0] == i + 1 && edges[k][1] == independent_set[j] + 1) || (edges[k][0] == independent_set[j] + 1 && edges[k][1] == i + 1)) {
                    is_unhappy = 1;
                    break;
                }
            }
            if (is_unhappy) {
                break;
            }
        }
        if (is_unhappy && !is_adjacent) {
            unhappy_cities++;
        }
    }
    printf("%d\n", happy_cities - unhappy_cities);
    return 0;
}

